@dataclass(frozen=True)
class EvidenceDetail:
    title: str
    collector: str
    ok_condition: str
    save_as: str


@dataclass(frozen=True)
class ScenarioStepDetail:
    component_title: str
    action_title: str
    state_title: str
    data_label: str
    target_label: str
    operation_steps: tuple[str, ...]
    setting_rows: tuple[tuple[str, str], ...]
    failure_trigger: str
    evidences: tuple[EvidenceDetail, ...]


def as_mapping(value: object) -> Mapping[str, object]:
    return cast(Mapping[str, object], value) if isinstance(value, dict) else {}


def as_sequence(value: object) -> Sequence[object]:
    return cast(Sequence[object], value) if isinstance(value, list | tuple) else ()


def load_yaml(path: Path) -> Mapping[str, object]:
    loaded = yaml.safe_load(path.read_text(encoding="utf-8"))
    return as_mapping(loaded)


def scalar_text(value: object, default: str = "-") -> str:
    return value if isinstance(value, str) else default


def sentence_body(value: str) -> str:
    return value.rstrip("。.")


def unique_texts(values: Sequence[str]) -> tuple[str, ...]:
    seen: set[str] = set()
    unique: list[str] = []
    for value in values:
        if value in seen:
            continue
        seen.add(value)
        unique.append(value)
    return tuple(unique)


def parse_component_variant(variant_id: str) -> tuple[str, str, str, str, str, str]:
    raw, data_id = variant_id.split("@", maxsplit=1) if "@" in variant_id else (variant_id, "-")
    parts = raw.split(".")
    component = parts[0] if len(parts) > 0 else "-"
    action = parts[1] if len(parts) > 1 else "-"
    project = "-"
    api = "-"
    state = parts[-1] if parts else "-"
    middle = parts[2:-1]
    for value in middle:
        if value.startswith("project_"):
            project = value
        elif value.startswith("API_"):
            api = value
    return component, action, project, api, state, data_id


def render_target_prerequisites(target_case: E2eTargetCase) -> list[str]:
    prerequisites = [
        "Cognito管理API用tokenを取得できる。",
        "case.id suffixでProject/APIなどのテストデータを一意に扱う。",
        "secret値、API key値、client secret値の実値をMarkdownやログに出さない。",
        "`${project_api_key}` と `${runtime_access_token}` はplaceholderとして扱う。",
    ]
    return [f"{index}. {text}" for index, text in enumerate(prerequisites, start=1)]


def render_target_runtime_assertions(target_case: E2eTargetCase) -> list[str]:
    if not target_case.runtime_assertions:
        return ["このケースでは Runtime API の呼び出し期待は設定しない。"]
    lines = ["Runtime API について、次の期待を確認する。"]
    for assertion in target_case.runtime_assertions:
        lines.append(
            f"- {target_title('project', assertion.project_id)} から "
            f"{target_title('api', assertion.api_id)} への呼び出しは"
            f"「{runtime_expectation_label(assertion.expected)}」として扱う。"
        )
    return lines


def component_yaml(component_id: str, filename: str) -> Mapping[str, object]:
    return load_yaml(Path("docs/spec/50.e2e") / FLOW_ID / "components" / component_id / filename)


def target_yaml(target_type: str, target_id: str) -> Mapping[str, object]:
    directory = "projects" if target_type == "project" else "apis"
    return load_yaml(
        Path("docs/spec/50.e2e")
        / FLOW_ID
        / "targets"
        / directory
        / f"{target_id}.target.manual.yaml"
    )


def target_title(target_type: str, target_id: str) -> str:
    if target_id == "-":
        return "-"
    target = as_mapping(target_yaml(target_type, target_id).get("target"))
    return scalar_text(target.get("title"), target_id)


def target_defaults(target_type: str, target_id: str) -> Mapping[str, object]:
    if target_id == "-":
        return {}
    return as_mapping(target_yaml(target_type, target_id).get("defaults"))


def component_title(component_id: str) -> str:
    component = as_mapping(component_yaml(component_id, "component.manual.yaml").get("component"))
    return scalar_text(component.get("title"), component_id)


def component_item(
    component_id: str,
    filename: str,
    collection_key: str,
    item_id: str,
) -> Mapping[str, object]:
    content = component_yaml(component_id, filename)
    for item in as_sequence(content.get(collection_key)):
        item_mapping = as_mapping(item)
        if item_mapping.get("id") == item_id:
            return item_mapping
    return {}


def component_item_title(
    component_id: str,
    filename: str,
    collection_key: str,
    item_id: str,
) -> str:
    return scalar_text(
        component_item(component_id, filename, collection_key, item_id).get("title"),
        item_id,
    )


def component_data_tags(component_id: str, data_id: str) -> set[str]:
    content = component_yaml(component_id, "data.manual.yaml")
    for item in as_sequence(content.get("data_profiles")):
        data = as_mapping(item)
        if data.get("id") == data_id:
            return {tag for tag in as_sequence(data.get("tags")) if isinstance(tag, str)}
    return set()


def component_data_profile(component_id: str, data_id: str) -> Mapping[str, object]:
    return component_item(component_id, "data.manual.yaml", "data_profiles", data_id)


def component_evidences(component_id: str) -> Mapping[str, Mapping[str, object]]:
    content = component_yaml(component_id, "evidences.manual.yaml")
    return {
        evidence_id: evidence
        for item in as_sequence(content.get("evidences"))
        for evidence in [as_mapping(item)]
        for evidence_id in [evidence.get("id")]
        if isinstance(evidence_id, str)
    }


def component_bindings(component_id: str) -> Sequence[Mapping[str, object]]:
    content = component_yaml(component_id, "bindings.manual.yaml")
    return [as_mapping(item) for item in as_sequence(content.get("bindings"))]


def step_description(step_ref: str) -> str:
    if step_ref == "manual_log_query":
        return "監査ログまたは運用ログを確認する"
    if not step_ref.startswith("steps/"):
        return step_ref
    content = load_yaml(Path("docs/spec/50.e2e") / FLOW_ID / step_ref)
    step = as_mapping(content.get("step"))
    title = scalar_text(step.get("title"), step_ref)
    endpoint = scalar_text(step.get("endpoint"), "")
    if endpoint:
        return f"{title} ({endpoint})"
    return title


def target_binding_matches(
    binding: Mapping[str, object],
    *,
    action_id: str,
    state_id: str,
    tags: set[str],
) -> bool:
    when = as_mapping(binding.get("when"))
    if when.get("action") not in (None, action_id):
        return False
    if when.get("state") not in (None, state_id):
        return False
    required_tags = {
        tag
        for tag in as_sequence(as_mapping(when.get("data_tags")).get("include"))
        if isinstance(tag, str)
    }
    return required_tags <= tags


def matching_bindings_for_variant(
    *,
    component_id: str,
    action_id: str,
    state_id: str,
    tags: set[str],
) -> tuple[Mapping[str, object], ...]:
    return tuple(
        binding
        for binding in component_bindings(component_id)
        if target_binding_matches(
            binding,
            action_id=action_id,
            state_id=state_id,
            tags=tags,
        )
    )


def expand_target_value(
    value: str,
    *,
    target_case: E2eTargetCase,
    project_id: str,
    api_id: str,
) -> str:
    return (
        value.replace("${case.id}", target_case.case_id)
        .replace("${project.id}", project_id)
        .replace("${api.id}", api_id)
        .replace("${foreach.api.id}", api_id)
    )


def expand_step_value(
    value: str,
    *,
    target_case: E2eTargetCase,
    project_id: str,
    api_id: str,
) -> str:
    expanded = expand_target_value(
        value,
        target_case=target_case,
        project_id=project_id,
        api_id=api_id,
    )
    replacements: dict[str, str] = {}
    for key, raw_value in target_defaults("project", project_id).items():
        if isinstance(raw_value, str):
            replacements[f"${{project.defaults.{key}}}"] = expand_target_value(
                raw_value,
                target_case=target_case,
                project_id=project_id,
                api_id=api_id,
            )
    for key, raw_value in target_defaults("api", api_id).items():
        if isinstance(raw_value, str):
            replacements[f"${{api.defaults.{key}}}"] = expand_target_value(
                raw_value,
                target_case=target_case,
                project_id=project_id,
                api_id=api_id,
            )
    for placeholder, concrete in replacements.items():
        expanded = expanded.replace(placeholder, concrete)
    return expanded


def format_setting_value(value: object) -> str:
    if isinstance(value, bool):
        return "true" if value else "false"
    if value is None:
        return "null"
    return str(value)


def flatten_settings(
    value: object,
    *,
    prefix: str,
    target_case: E2eTargetCase,
    project_id: str,
    api_id: str,
) -> list[tuple[str, str]]:
    if isinstance(value, Mapping):
        rows: list[tuple[str, str]] = []
        mapping = cast(Mapping[object, object], value)
        for key, child in mapping.items():
            key_text = str(key)
            child_prefix = f"{prefix}.{key_text}" if prefix else key_text
            rows.extend(
                flatten_settings(
                    child,
                    prefix=child_prefix,
                    target_case=target_case,
                    project_id=project_id,
                    api_id=api_id,
                )
            )
        return rows
    if isinstance(value, Sequence) and not isinstance(value, str):
        rows: list[tuple[str, str]] = []
        sequence = cast(Sequence[object], value)
        for index, child in enumerate(sequence):
            rows.extend(
                flatten_settings(
                    child,
                    prefix=f"{prefix}[{index}]",
                    target_case=target_case,
                    project_id=project_id,
                    api_id=api_id,
                )
            )
        return rows
    raw_value = format_setting_value(value)
    return [
        (
            prefix,
            expand_step_value(
                raw_value,
                target_case=target_case,
                project_id=project_id,
                api_id=api_id,
            ),
        )
    ]


def setting_rows_for_variant(
    *,
    target_case: E2eTargetCase,
    component_id: str,
    action_id: str,
    state_id: str,
    data_id: str,
    project_id: str,
    api_id: str,
) -> tuple[tuple[str, str], ...]:
    data_profile = component_data_profile(component_id, data_id)
    rows: list[tuple[str, str]] = []
    request = as_mapping(data_profile.get("request"))
    expected = as_mapping(data_profile.get("expected"))
    if request:
        rows.extend(
            flatten_settings(
                request,
                prefix="request",
                target_case=target_case,
                project_id=project_id,
                api_id=api_id,
            )
        )
    if expected:
        rows.extend(
            flatten_settings(
                expected,
                prefix="expected",
                target_case=target_case,
                project_id=project_id,
                api_id=api_id,
            )
        )
    rows.extend(
        error_setting_rows(
            component_id=component_id,
            action_id=action_id,
            state_id=state_id,
            data_id=data_id,
            project_id=project_id,
            api_id=api_id,
            target_case=target_case,
        )
    )
    return tuple(rows)


def target_label(project_id: str, api_id: str) -> str:
    labels = [
        label
        for label in (
            target_title("project", project_id) if project_id != "-" else "",
            target_title("api", api_id) if api_id != "-" else "",
        )
        if label
    ]
    return " と ".join(labels) if labels else "フロー全体"


def concrete_data_label(
    *,
    component_id: str,
    data_id: str,
    project_id: str,
    api_id: str,
) -> str:
    data_title = component_item_title(
        component_id,
        "data.manual.yaml",
        "data_profiles",
        data_id,
    )
    target = target_label(project_id, api_id)
    if data_id in {
        "api_default",
        "api_unknown",
    }:
        return target_title("api", api_id)
    if data_id in {
        "project_default",
        "redirect_url_update",
    }:
        return target_title("project", project_id)
    concrete_labels = {
        "request_both_auth": "利用申請",
        "duplicate_pending_request": "重複PENDING申請",
        "approve_both": "承認",
        "reject_default": "却下",
        "approved_both_entitlement": "利用権",
        "rejected_no_entitlement": "却下後の利用権なし",
        "provisioning_retry": "provisioning再試行",
    }
    if data_id in concrete_labels and target != "フロー全体":
        return f"{target} の{concrete_labels[data_id]}"
    if target != "フロー全体":
        return f"{target} の{data_title}"
    return data_title


def error_setting_rows(
    *,
    component_id: str,
    action_id: str,
    state_id: str,
    data_id: str,
    project_id: str,
    api_id: str,
    target_case: E2eTargetCase,
) -> tuple[tuple[str, str], ...]:
    api = target_title("api", api_id)
    project = target_title("project", project_id)
    api_code = expand_step_value(
        "${api.defaults.apiCode}",
        target_case=target_case,
        project_id=project_id,
        api_id=api_id,
    )
    project_code = expand_step_value(
        "${project.defaults.projectCode}",
        target_case=target_case,
        project_id=project_id,
        api_id=api_id,
    )
    rows = {
        ("api_catalog", "publish_api", "publish_failed", "api_default"): (
            ("error.precondition", f"{api} is already published with apiCode={api_code}"),
        ),
        ("api_catalog", "browse_api", "not_found", "api_unknown"): (
            ("request.path.apiId", "api_unknown"),
            ("error.reason", "指定した apiId が API catalog に存在しない"),
        ),
        ("project_workspace", "create_project", "provision_failed", "project_default"): (
            (
                "error.precondition",
                f"{project} is already created with projectCode={project_code}",
            ),
        ),
        (
            "project_workspace",
            "update_public_client",
            "public_client_update_failed",
            "redirect_url_update",
        ): (
            (
                "error.override.callbackUrls[0]",
                "https://malformed.example.invalid/callback",
            ),
            ("error.reason", "許可されない redirect URI を含める"),
        ),
        (
            "access_request_workflow",
            "submit_request",
            "duplicate_pending_rejected",
            "duplicate_pending_request",
        ): (
            ("error.precondition", f"{project} x {api} のPENDING申請が存在する"),
        ),
        (
            "access_request_workflow",
            "submit_request",
            "existing_subscription_rejected",
            "request_both_auth",
        ): (
            ("error.precondition", f"{project} x {api} のACTIVE subscriptionが存在する"),
        ),
        ("review_decision", "approve_request", "forbidden", "approve_both"): (
            ("error.actor", "reviewer ではない管理主体"),
        ),
        ("review_decision", "approve_request", "not_pending", "approve_both"): (
            ("error.notPendingState", "APPROVED または REJECTED"),
        ),
        ("review_decision", "reject_request", "forbidden", "reject_default"): (
            ("error.actor", "reviewer ではない管理主体"),
        ),
        ("review_decision", "reject_request", "not_pending", "reject_default"): (
            ("error.notPendingState", "APPROVED または REJECTED"),
        ),
        (
            "entitlement_provisioning",
            "provision_entitlement",
            "partially_failed",
            "approved_both_entitlement",
        ): (
            ("error.injectedFailure", "Usage Plan stage または Cognito scope の片方を失敗させる"),
        ),
        (
            "runtime_authorization",
            "invoke_runtime_api",
            "credential_invalid",
            "scope_missing",
        ): (
            ("error.token", "custom scope を含まない access token"),
        ),
        (
            "runtime_authorization",
            "invoke_runtime_api",
            "credential_invalid",
            "api_key_missing",
        ): (
            ("error.header.x-api-key", "送信しない"),
        ),
    }
    return rows.get((component_id, action_id, state_id, data_id), ())


def failure_trigger_for_variant(
    *,
    component_id: str,
    action_id: str,
    state_id: str,
    data_id: str,
    project_id: str,
    api_id: str,
    target_case: E2eTargetCase,
) -> str:
    api = target_title("api", api_id)
    project = target_title("project", project_id)
    api_code = expand_step_value(
        "${api.defaults.apiCode}",
        target_case=target_case,
        project_id=project_id,
        api_id=api_id,
    )
    project_code = expand_step_value(
        "${project.defaults.projectCode}",
        target_case=target_case,
        project_id=project_id,
        api_id=api_id,
    )
    triggers = {
        ("api_catalog", "publish_api", "publish_failed", "api_default"): (
            f"{api} を同じ `apiCode={api_code}` で事前に公開済みにし、"
            "同じ API code で再度 API 公開を実行して重複エラーを発生させる。"
        ),
        ("api_catalog", "browse_api", "not_found", "api_unknown"): (
            "存在しない `apiId=api_unknown` を指定して API 詳細を取得し、"
            "未登録 API の 404 を発生させる。"
        ),
        ("project_workspace", "create_project", "provision_failed", "project_default"): (
            f"{project} を同じ `projectCode={project_code}` で事前に作成済みにし、"
            "同じ Project code で再度 Project 作成を実行して重複エラーを発生させる。"
        ),
        (
            "project_workspace",
            "update_public_client",
            "public_client_update_failed",
            "redirect_url_update",
        ): (
            f"{project} の public app client 更新で、許可されない redirect URI "
            "または既存設定と矛盾する callback/logout URL を含めて検証エラーを発生させる。"
        ),
        (
            "access_request_workflow",
            "submit_request",
            "duplicate_pending_rejected",
            "duplicate_pending_request",
        ): (
            f"{project} から {api} への PENDING 申請を事前に作成し、"
            "同じ Project/API stage へ再申請して重複 PENDING エラーを発生させる。"
        ),
        (
            "access_request_workflow",
            "submit_request",
            "existing_subscription_rejected",
            "request_both_auth",
        ): (
            f"{project} と {api} の ACTIVE subscription を事前に作成し、"
            "既に利用権がある API へ再申請して 409 を発生させる。"
        ),
        ("review_decision", "approve_request", "forbidden", "approve_both"): (
            "対象 API の reviewer ではない管理主体の token で承認 API を呼び出し、"
            "403 を発生させる。"
        ),
        ("review_decision", "reject_request", "forbidden", "reject_default"): (
            "対象 API の reviewer ではない管理主体の token で却下 API を呼び出し、"
            "403 を発生させる。"
        ),
        ("review_decision", "approve_request", "not_pending", "approve_both"): (
            "対象の利用申請を事前に APPROVED または REJECTED にしてから承認 API を呼び出し、"
            "PENDING 以外の審査エラーを発生させる。"
        ),
        ("review_decision", "reject_request", "not_pending", "reject_default"): (
            "対象の利用申請を事前に APPROVED または REJECTED にしてから却下 API を呼び出し、"
            "PENDING 以外の審査エラーを発生させる。"
        ),
        (
            "entitlement_provisioning",
            "provision_entitlement",
            "partially_failed",
            "approved_both_entitlement",
        ): (
            "Usage Plan stage 反映または Cognito scope 反映の片方だけが失敗する状態を用意し、"
            "承認処理で部分失敗と retry 可能な provisioning operation を発生させる。"
        ),
        (
            "runtime_authorization",
            "invoke_runtime_api",
            "credential_invalid",
            "scope_missing",
        ): (
            f"{project} と {api} の subscription は有効にしたまま、"
            "必要な custom scope を含まない access token で Runtime API を呼び出す。"
        ),
        (
            "runtime_authorization",
            "invoke_runtime_api",
            "credential_invalid",
            "api_key_missing",
        ): (
            f"{project} と {api} の subscription は有効にしたまま、"
            "`x-api-key` ヘッダーを送らずに Runtime API を呼び出す。"
        ),
    }
    return triggers.get((component_id, action_id, state_id, data_id), "")


def runtime_expectation_label(expected: str) -> str:
    return {
        "allowed": "許可される",
        "denied": "拒否される",
    }.get(expected, expected)


def evidence_details_for_variant(
    *,
    target_case: E2eTargetCase,
    component_id: str,
    action_id: str,
    state_id: str,
    data_id: str,
    project_id: str,
    api_id: str,
) -> tuple[EvidenceDetail, ...]:
    tags = component_data_tags(component_id, data_id)
    evidence_map = component_evidences(component_id)
    details: list[EvidenceDetail] = []
    for binding in matching_bindings_for_variant(
        component_id=component_id,
        action_id=action_id,
        state_id=state_id,
        tags=tags,
    ):
        for evidence_ref in as_sequence(binding.get("evidences")):
            evidence_id = as_mapping(evidence_ref).get("ref")
            if not isinstance(evidence_id, str) or evidence_id not in evidence_map:
                continue
            evidence = evidence_map[evidence_id]
            collector = as_mapping(evidence.get("collector"))
            details.append(
                EvidenceDetail(
                    title=scalar_text(evidence.get("title")),
                    collector=step_description(scalar_text(collector.get("step"))),
                    ok_condition=expand_target_value(
                        scalar_text(evidence.get("ok_condition")),
                        target_case=target_case,
                        project_id=project_id,
                        api_id=api_id,
                    ),
                    save_as=expand_target_value(
                        scalar_text(evidence.get("save_as")),
                        target_case=target_case,
                        project_id=project_id,
                        api_id=api_id,
                    ),
                )
            )
    return tuple(details)


def operation_steps_for_variant(
    *,
    component_id: str,
    action_id: str,
    state_id: str,
    data_id: str,
) -> tuple[str, ...]:
    tags = component_data_tags(component_id, data_id)
    refs = [
        ref
        for binding in matching_bindings_for_variant(
            component_id=component_id,
            action_id=action_id,
            state_id=state_id,
            tags=tags,
        )
        for step_ref in as_sequence(binding.get("steps"))
        for ref in [as_mapping(step_ref).get("ref")]
        if isinstance(ref, str)
    ]
    return unique_texts(tuple(step_description(ref) for ref in refs))


def build_scenario_steps(target_case: E2eTargetCase) -> tuple[ScenarioStepDetail, ...]:
    steps: list[ScenarioStepDetail] = []
    for variant_id in target_case.selected_variants:
        component_id, action_id, project_id, api_id, state_id, data_id = parse_component_variant(
            variant_id
        )
        steps.append(
            ScenarioStepDetail(
                component_title=component_title(component_id),
                action_title=component_item_title(
                    component_id, "actions.manual.yaml", "actions", action_id
                ),
                state_title=component_item_title(
                    component_id, "states.manual.yaml", "states", state_id
                ),
                data_label=concrete_data_label(
                    component_id=component_id,
                    data_id=data_id,
                    project_id=project_id,
                    api_id=api_id,
                ),
                target_label=target_label(project_id, api_id),
                operation_steps=operation_steps_for_variant(
                    component_id=component_id,
                    action_id=action_id,
                    state_id=state_id,
                    data_id=data_id,
                ),
                setting_rows=setting_rows_for_variant(
                    target_case=target_case,
                    component_id=component_id,
                    action_id=action_id,
                    state_id=state_id,
                    data_id=data_id,
                    project_id=project_id,
                    api_id=api_id,
                ),
                failure_trigger=failure_trigger_for_variant(
                    component_id=component_id,
                    action_id=action_id,
                    state_id=state_id,
                    data_id=data_id,
                    project_id=project_id,
                    api_id=api_id,
                    target_case=target_case,
                ),
                evidences=evidence_details_for_variant(
                    target_case=target_case,
                    component_id=component_id,
                    action_id=action_id,
                    state_id=state_id,
                    data_id=data_id,
                    project_id=project_id,
                    api_id=api_id,
                ),
            )
        )
    return tuple(steps)


def render_step_detail(index: int, step: ScenarioStepDetail) -> list[str]:
    operation_text = "、".join(step.operation_steps) if step.operation_steps else step.action_title
    setting_lines = ["| 項目 | 値 |", "|---|---|"]
    if step.setting_rows:
        setting_lines.extend(
            f"| `{markdown_escape(key)}` | `{markdown_escape(value)}` |"
            for key, value in step.setting_rows
        )
    else:
        setting_lines.append("| - | 設定値なし |")
    evidence_lines = [
        (
            f"- {markdown_escape(evidence.title)}。取得方法は"
            f"{markdown_escape(evidence.collector)}。"
            f"確認条件は{markdown_escape(sentence_body(evidence.ok_condition))}。"
            f"保存名は `{evidence.save_as}`。"
        )
        for evidence in step.evidences
    ]
    if not evidence_lines:
        evidence_lines = ["- この Step で保存するエビデンスは定義されていない。"]
    return [
        f"### Step {index}: {markdown_escape(step.action_title)}",
        "",
        "#### 目的",
        "",
        (
            f"{step.target_label} に対して {step.component_title} の"
            f"「{markdown_escape(step.action_title)}」を実行し、"
            f"「{markdown_escape(step.state_title)}」を確認する。"
        ),
        "",
        "#### 操作",
        "",
        (
            f"{markdown_escape(operation_text)} を実行する。"
            f"対象データは「{markdown_escape(step.data_label)}」を使う。"
        ),
        *(
            [
                "",
                "失敗を発生させるため、"
                f"{markdown_escape(step.failure_trigger)}",
            ]
            if step.failure_trigger
            else []
        ),
        "",
        "#### 設定値",
        "",
        *setting_lines,
        "",
        "#### 確認観点",
        "",
        (
            f"この Step では、操作結果が「{markdown_escape(step.state_title)}」として"
            "観測できることを確認する。"
        ),
        "",
        "#### エビデンス",
        "",
        *evidence_lines,
        "",
    ]


def render_target_steps(target_case: E2eTargetCase) -> list[str]:
    lines: list[str] = []
    for index, step in enumerate(build_scenario_steps(target_case), start=1):
        lines.extend(render_step_detail(index, step))
    return lines


def goal_description(target_case: E2eTargetCase) -> str:
    component_id, action_id, project_id, api_id, state_id, data_id = parse_component_variant(
        target_case.goal_variant
    )
    action_title = component_item_title(
        component_id, "actions.manual.yaml", "actions", action_id
    )
    state_title = component_item_title(component_id, "states.manual.yaml", "states", state_id)
    data_label = concrete_data_label(
        component_id=component_id,
        data_id=data_id,
        project_id=project_id,
        api_id=api_id,
    )
    return (
        f"{target_label(project_id, api_id)} に対して "
        f"{component_title(component_id)} の「{action_title}」を実行し、"
        f"「{state_title}」を「{data_label}」で確認する。"
    )


def goal_component_title(target_case: E2eTargetCase) -> str:
    component_id, *_ = parse_component_variant(target_case.goal_variant)
    return component_title(component_id)


def render_target_scenario_markdown(target_case: E2eTargetCase) -> str:
    description = goal_description(target_case)
    lines = [
        GENERATED_COMMENT,
        "",
        f"# {target_case.case_id} {goal_component_title(target_case)}",
        "",
        "## 1. 対象",
        "",
        description,
        "",
        "## 2. 処理概要",
        "",
        f"このケースでは、{sentence_body(description)}までを一連の E2E 手順として確認する。",
        "",
        "## 3. 処理詳細",
        "",
        "### 前提条件",
        "",
        *render_target_prerequisites(target_case),
        "",
        *render_target_steps(target_case),
        "## 4. 後続確認",
        "",
        *render_target_runtime_assertions(target_case),
        "",
        f"- {target_case.case_id} が生成ケース一覧のシナリオリンクから参照できる。",
        "- 実行時のsecret値、API key値、client secret値は記録しない。",
        "",
    ]
    return "\n".join(lines)


def rendered_outputs(
    output_root: Path = Path("docs/spec/50.e2e"),
    *,
    spec_root: Path = Path("docs/spec/50.e2e"),
) -> Mapping[Path, str]:
    cases_root = output_root / FLOW_ID / "cases"
    return {
        cases_root / target_case.filename: render_target_scenario_markdown(target_case)
        for target_case in TARGET_CASES
    }


def generate(*, check: bool = False, output_root: Path = Path("docs/spec/50.e2e")) -> int:
    rendered = rendered_outputs(output_root)
    if check:
        return check_outputs(rendered)
    write_outputs(rendered)
    return 0


def main(argv: Sequence[str] | None = None) -> int:
    parser = argparse.ArgumentParser()
    parser.add_argument("--check", action="store_true")
    args = parser.parse_args(argv)
    return generate(check=args.check)


if __name__ == "__main__":
    raise SystemExit(main())
